-- ============================================================================
-- Quiz Seed: Hebrews — Part 2 (Chapters 8–13)
-- 3 difficulties × 6 chapters = 96 total questions
--   kids:   3 per chapter  = 18
--   teens:  5 per chapter  = 30
--   adults: 8 per chapter  = 48
-- ============================================================================

-- ═══════════════ CHAPTERS 8–10 ═══════════════

-- ═══ Hebrews Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Hebrews', 8, 'kids', 1, 'Where is Jesus serving as our high priest?', 'In heaven, at the right hand of the throne of the Majesty in the heavens', 'In the temple in Jerusalem', 'In a tent in the wilderness', 'In a church building on earth', 'a', 'Hebrews 8:1 — "We have such an high priest, who is set on the right hand of the throne of the Majesty in the heavens."'),
('Hebrews', 8, 'kids', 2, 'Did God make a new agreement (covenant) with his people?', 'Yes, God made a new covenant that is better than the old one', 'No, the old covenant is still the only one', 'He made the same covenant again', 'He cancelled all agreements', 'a', 'Hebrews 8:8 — "Behold, the days come, saith the Lord, when I will make a new covenant with the house of Israel."'),
('Hebrews', 8, 'kids', 3, 'Where does God promise to write his laws under the new covenant?', 'In our minds and in our hearts', 'On stone tablets', 'On scrolls of paper', 'On the walls of the temple', 'a', 'Hebrews 8:10 — "I will put my laws into their mind, and write them in their hearts."'),
-- Teens
('Hebrews', 8, 'teens', 1, 'What is Jesus the minister of in heaven?', 'The sanctuary and the true tabernacle which the Lord pitched, and not man', 'The earthly temple in Jerusalem', 'A tent made by Moses', 'A building constructed by Solomon', 'a', 'Hebrews 8:2 — "A minister of the sanctuary, and of the true tabernacle, which the Lord pitched, and not man."'),
('Hebrews', 8, 'teens', 2, 'What was the earthly tabernacle a copy of?', 'The pattern showed to Moses in the mount — a shadow of heavenly things', 'An original design by Moses himself', 'A standard building of that era', 'A copy of Egyptian temples', 'a', 'Hebrews 8:5 — "Who serve unto the example and shadow of heavenly things, as Moses was admonished of God when he was about to make the tabernacle: for, See, saith he, that thou make all things according to the pattern shewed to thee in the mount."'),
('Hebrews', 8, 'teens', 3, 'What does the new covenant promise about knowing God?', 'They shall not teach every man his neighbour saying Know the Lord, for all shall know me from the least to the greatest', 'Only priests will know God', 'Knowledge of God will be limited to scholars', 'People must be taught for many years to know God', 'a', 'Hebrews 8:11 — "And they shall not teach every man his neighbour, and every man his brother, saying, Know the Lord: for all shall know me, from the least to the greatest."'),
('Hebrews', 8, 'teens', 4, 'What does God promise about sins under the new covenant?', 'I will be merciful to their unrighteousness, and their sins and their iniquities will I remember no more', 'Sins will be remembered but forgiven partially', 'Sins must be atoned for yearly by sacrifice', 'Only small sins will be forgiven', 'a', 'Hebrews 8:12 — "For I will be merciful to their unrighteousness, and their sins and their iniquities will I remember no more."'),
('Hebrews', 8, 'teens', 5, 'What happened to the first covenant when God made a new one?', 'He hath made the first old — that which decayeth and waxeth old is ready to vanish away', 'The first covenant became stronger', 'Both covenants continue with equal authority', 'The first covenant was improved slightly', 'a', 'Hebrews 8:13 — "In that he saith, A new covenant, he hath made the first old. Now that which decayeth and waxeth old is ready to vanish away."'),
-- Adults
('Hebrews', 8, 'adults', 1, 'What is the "sum" or main point of the author''s argument?', 'We have such an high priest who is set on the right hand of the throne of the Majesty in the heavens, a minister of the sanctuary and the true tabernacle', 'The law must still be observed perfectly', 'The earthly temple is the centre of worship', 'Animal sacrifices remain necessary', 'a', 'Hebrews 8:1-2 — "Now of the things which we have spoken this is the sum: We have such an high priest, who is set on the right hand of the throne of the Majesty in the heavens; A minister of the sanctuary, and of the true tabernacle, which the Lord pitched, and not man."'),
('Hebrews', 8, 'adults', 2, 'Why was a new covenant needed according to verse 7?', 'If the first covenant had been faultless, then should no place have been sought for the second', 'The first covenant was perfect and complete', 'God changed his mind arbitrarily', 'The people requested a new agreement', 'a', 'Hebrews 8:7 — "For if that first covenant had been faultless, then should no place have been sought for the second."'),
('Hebrews', 8, 'adults', 3, 'Where does the author find fault with the first covenant?', 'Finding fault with them — the people could not keep it; the new covenant addresses this by writing the law on hearts and minds', 'The fault was in God''s design', 'The fault was in the wording of the covenant', 'There was no fault with the first covenant', 'a', 'Hebrews 8:8 — "For finding fault with them, he saith, Behold, the days come, saith the Lord, when I will make a new covenant."'),
('Hebrews', 8, 'adults', 4, 'What long prophecy does the author quote about the new covenant?', 'Jeremiah 31:31-34 — the new covenant with Israel and Judah, laws in minds and hearts, universal knowledge of God, and complete forgiveness', 'Isaiah 53 — the suffering servant', 'Ezekiel 37 — the valley of dry bones', 'Daniel 9 — the seventy weeks prophecy', 'a', 'Hebrews 8:8-12 quotes Jeremiah 31:31-34, the longest Old Testament quotation in the New Testament.'),
('Hebrews', 8, 'adults', 5, 'What does the new covenant being "not according to the covenant I made with their fathers" signify?', 'A fundamentally different covenant — not merely a renewal of the old, because they broke the old covenant despite God''s faithfulness', 'A minor revision of the same agreement', 'An extension of the same terms', 'A temporary replacement until the old is restored', 'a', 'Hebrews 8:9 — "Not according to the covenant that I made with their fathers in the day when I took them by the hand to lead them out of the land of Egypt; because they continued not in my covenant, and I regarded them not, saith the Lord."'),
('Hebrews', 8, 'adults', 6, 'What does Christ''s "more excellent ministry" establish him as?', 'The mediator of a better covenant, which was established upon better promises', 'A mediator equal to Moses', 'A mediator of the same covenant with different terms', 'A temporary mediator until a better one comes', 'a', 'Hebrews 8:6 — "But now hath he obtained a more excellent ministry, by how much also he is the mediator of a better covenant, which was established upon better promises."'),
('Hebrews', 8, 'adults', 7, 'What does the phrase "I will be to them a God, and they shall be to me a people" express?', 'The covenant formula of intimate relationship — God claims his people as his own and they recognize him as their God, the heart of all biblical covenants', 'A simple legal arrangement', 'A temporary political alliance', 'A conditional agreement based on performance', 'a', 'Hebrews 8:10 — "I will be to them a God, and they shall be to me a people." This is the covenant formula found throughout Scripture (cf. Exodus 6:7, Leviticus 26:12).'),
('Hebrews', 8, 'adults', 8, 'What does the author conclude about the first covenant in verse 13?', 'By saying "a new covenant" God has made the first old — what is obsolete and growing old is ready to vanish away, implying the old covenant system was passing away', 'The first covenant will be renewed and strengthened', 'The first covenant is eternal and unchanging', 'Both covenants will continue forever side by side', 'a', 'Hebrews 8:13 — "In that he saith, A new covenant, he hath made the first old. Now that which decayeth and waxeth old is ready to vanish away."');

-- ═══ Hebrews Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Hebrews', 9, 'kids', 1, 'What did Jesus use to enter the holy place instead of animal blood?', 'His own blood', 'The blood of goats', 'The blood of bulls', 'Water from the river', 'a', 'Hebrews 9:12 — "Neither by the blood of goats and calves, but by his own blood he entered in once into the holy place, having obtained eternal redemption for us."'),
('Hebrews', 9, 'kids', 2, 'How many times does a person die?', 'Once — it is appointed unto men once to die', 'Twice', 'Three times', 'As many times as they want', 'a', 'Hebrews 9:27 — "And as it is appointed unto men once to die, but after this the judgment."'),
('Hebrews', 9, 'kids', 3, 'How many times did Jesus need to offer himself as a sacrifice?', 'Once — he appeared once to put away sin by the sacrifice of himself', 'Every year like the old priests', 'Every day', 'Many times over and over', 'a', 'Hebrews 9:26 — "But now once in the end of the world hath he appeared to put away sin by the sacrifice of himself."'),
-- Teens
('Hebrews', 9, 'teens', 1, 'What was in the first tabernacle and the second (Holy of Holies)?', 'The first had the candlestick, table, and shewbread; the second had the golden censer, the ark of the covenant covered with the mercy seat and cherubims', 'Both rooms were empty', 'The first had the ark and the second was empty', 'They contained Roman idols', 'a', 'Hebrews 9:2-5 describes the furnishings: "the first, wherein was the candlestick, and the table, and the shewbread... the Holiest of all; Which had the golden censer, and the ark of the covenant."'),
('Hebrews', 9, 'teens', 2, 'How often did the high priest enter the Holy of Holies?', 'Once every year alone, not without blood which he offered for himself and for the errors of the people', 'Every day at morning prayer', 'Every week on the Sabbath', 'Whenever he wanted to', 'a', 'Hebrews 9:7 — "But into the second went the high priest alone once every year, not without blood, which he offered for himself, and for the errors of the people."'),
('Hebrews', 9, 'teens', 3, 'What did Christ obtain by entering with his own blood?', 'Eternal redemption for us', 'Temporary forgiveness lasting one year', 'A promise of future salvation', 'Only ceremonial cleansing', 'a', 'Hebrews 9:12 — "Neither by the blood of goats and calves, but by his own blood he entered in once into the holy place, having obtained eternal redemption for us."'),
('Hebrews', 9, 'teens', 4, 'What does Christ''s blood purge our conscience from?', 'Dead works to serve the living God', 'All physical diseases', 'All emotional pain', 'All financial debts', 'a', 'Hebrews 9:14 — "How much more shall the blood of Christ, who through the eternal Spirit offered himself without spot to God, purge your conscience from dead works to serve the living God?"'),
('Hebrews', 9, 'teens', 5, 'What comes after death for all people?', 'The judgment — as it is appointed unto men once to die, but after this the judgment', 'Reincarnation into another life', 'Nothing at all happens', 'A second chance to live again', 'a', 'Hebrews 9:27 — "And as it is appointed unto men once to die, but after this the judgment."'),
-- Adults
('Hebrews', 9, 'adults', 1, 'What was the Holy Ghost signifying by the structure of the tabernacle?', 'That the way into the holiest of all was not yet made manifest while the first tabernacle was yet standing', 'That the tabernacle was the final form of worship', 'That only priests could ever approach God', 'That the structure had no deeper meaning', 'a', 'Hebrews 9:8 — "The Holy Ghost this signifying, that the way into the holiest of all was not yet made manifest, while as the first tabernacle was yet standing."'),
('Hebrews', 9, 'adults', 2, 'How does the author contrast Christ''s sacrifice with animal sacrifices?', 'If the blood of bulls and goats sanctifieth to the purifying of the flesh, how much more shall the blood of Christ purge your conscience from dead works', 'Animal sacrifices were equally effective', 'Christ''s sacrifice was merely symbolic', 'Both types of sacrifice achieve the same result', 'a', 'Hebrews 9:13-14 — "For if the blood of bulls and of goats, and the ashes of an heifer sprinkling the unclean, sanctifieth to the purifying of the flesh: How much more shall the blood of Christ... purge your conscience from dead works to serve the living God?"'),
('Hebrews', 9, 'adults', 3, 'What does "without shedding of blood is no remission" establish?', 'The absolute necessity of blood atonement — the shedding of blood is indispensable for the forgiveness of sins under God''s economy', 'Blood shedding is optional for forgiveness', 'Only symbolic blood is needed', 'Forgiveness requires good works, not blood', 'a', 'Hebrews 9:22 — "And almost all things are by the law purged with blood; and without shedding of blood is no remission."'),
('Hebrews', 9, 'adults', 4, 'Where did Christ enter to appear in the presence of God for us?', 'Into heaven itself — not into the holy places made with hands which are the figures of the true', 'Into the earthly temple in Jerusalem', 'Into a replica of the tabernacle', 'Into a heavenly tabernacle made with hands', 'a', 'Hebrews 9:24 — "For Christ is not entered into the holy places made with hands, which are the figures of the true; but into heaven itself, now to appear in the presence of God for us."'),
('Hebrews', 9, 'adults', 5, 'Why did Christ not need to offer himself often?', 'Then must he often have suffered since the foundation of the world — but now once in the end of the world hath he appeared to put away sin by the sacrifice of himself', 'His sacrifice was only partially effective', 'Multiple offerings would increase his merit', 'The first offering was merely a trial', 'a', 'Hebrews 9:25-26 — "Nor yet that he should offer himself often, as the high priest entereth into the holy place every year with blood of others; For then must he often have suffered since the foundation of the world: but now once in the end of the world hath he appeared to put away sin by the sacrifice of himself."'),
('Hebrews', 9, 'adults', 6, 'What does the author say about a testament (covenant) and death?', 'Where a testament is, there must also of necessity be the death of the testator — a testament is of force after men are dead', 'Testaments can be enacted without death', 'Death is irrelevant to covenant making', 'Any person can activate a testament at any time', 'a', 'Hebrews 9:16-17 — "For where a testament is, there must also of necessity be the death of the testator. For a testament is of force after men are dead: otherwise it is of no strength at all while the testator liveth."'),
('Hebrews', 9, 'adults', 7, 'What three appearances of Christ does the author describe?', 'He appeared once to put away sin (past), now appears in the presence of God for us (present), and shall appear the second time without sin unto salvation (future)', 'He appeared only once in history', 'He appears continuously in the temple', 'He will not appear again', 'a', 'Hebrews 9:26,24,28 describes Christ''s past appearance for sacrifice, present appearance before God, and future appearance for salvation.'),
('Hebrews', 9, 'adults', 8, 'What does "Christ was once offered to bear the sins of many" connect to?', 'Isaiah 53:12 — the Suffering Servant who bore the sins of many; his second coming will be apart from sin, unto salvation for those who look for him', 'A general teaching about moral improvement', 'A reference to the Day of Atonement goat only', 'A political statement about liberation', 'a', 'Hebrews 9:28 — "So Christ was once offered to bear the sins of many; and unto them that look for him shall he appear the second time without sin unto salvation." This echoes Isaiah 53:12.');

-- ═══ Hebrews Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Hebrews', 10, 'kids', 1, 'Can the blood of bulls and goats really take away sins?', 'No, it is not possible for the blood of bulls and goats to take away sins', 'Yes, it works perfectly', 'Only sometimes', 'Only if you use enough blood', 'a', 'Hebrews 10:4 — "For it is not possible that the blood of bulls and of goats should take away sins."'),
('Hebrews', 10, 'kids', 2, 'Should we stop meeting together as Christians?', 'No — we should not forsake the assembling of ourselves together', 'Yes, we should worship alone', 'Only meet on holidays', 'Meeting together doesn''t matter', 'a', 'Hebrews 10:25 — "Not forsaking the assembling of ourselves together."'),
('Hebrews', 10, 'kids', 3, 'What should we hold fast to without wavering?', 'The profession of our faith — because God is faithful who promised', 'Our favourite toys', 'Our money and treasures', 'Our popularity', 'a', 'Hebrews 10:23 — "Let us hold fast the profession of our faith without wavering; (for he is faithful that promised.)"'),
-- Teens
('Hebrews', 10, 'teens', 1, 'What did the old sacrifices remind people of every year?', 'Their sins — there is a remembrance again made of sins every year', 'Their victories in battle', 'Their wealth and prosperity', 'Their ancestors'' accomplishments', 'a', 'Hebrews 10:3 — "But in those sacrifices there is a remembrance again made of sins every year."'),
('Hebrews', 10, 'teens', 2, 'What did Jesus say when he came into the world?', 'Sacrifice and offering thou wouldest not, but a body hast thou prepared me — Lo, I come to do thy will, O God', 'I come to conquer the nations', 'I come to build a great temple', 'I come to establish an earthly kingdom', 'a', 'Hebrews 10:5,7 — "Sacrifice and offering thou wouldest not, but a body hast thou prepared me... Lo, I come (in the volume of the book it is written of me,) to do thy will, O God."'),
('Hebrews', 10, 'teens', 3, 'What new way has Jesus opened for us?', 'A new and living way through the veil, that is to say, his flesh', 'A new road to Jerusalem', 'A new trade route to Rome', 'A new path through the wilderness', 'a', 'Hebrews 10:20 — "By a new and living way, which he hath consecrated for us, through the veil, that is to say, his flesh."'),
('Hebrews', 10, 'teens', 4, 'What should we consider about one another?', 'How to provoke one another unto love and to good works', 'How to compete with each other', 'How to judge one another''s faults', 'How to avoid one another', 'a', 'Hebrews 10:24 — "And let us consider one another to provoke unto love and to good works."'),
('Hebrews', 10, 'teens', 5, 'What is described as a fearful thing?', 'It is a fearful thing to fall into the hands of the living God', 'It is fearful to speak in public', 'It is fearful to travel the seas', 'It is fearful to face wild animals', 'a', 'Hebrews 10:31 — "It is a fearful thing to fall into the hands of the living God."'),
-- Adults
('Hebrews', 10, 'adults', 1, 'What does the law having "a shadow of good things to come" mean?', 'The law was a foreshadowing or type of the heavenly realities fulfilled in Christ — not the very image, so it could never make comers thereunto perfect', 'The law was the final and complete revelation', 'The shadow was superior to the reality', 'The law had no connection to Christ', 'a', 'Hebrews 10:1 — "For the law having a shadow of good things to come, and not the very image of the things, can never with those sacrifices which they offered year by year continually make the comers thereunto perfect."'),
('Hebrews', 10, 'adults', 2, 'What Psalm does the author quote about God''s desire versus sacrifice?', 'Psalm 40:6-8 — "Sacrifice and offering thou wouldest not, but a body hast thou prepared me... Lo, I come to do thy will, O God"', 'Psalm 51 — The sacrifices of God are a broken spirit', 'Psalm 23 — The Lord is my shepherd', 'Psalm 110 — Sit thou at my right hand', 'a', 'Hebrews 10:5-7 quotes Psalm 40:6-8, showing Christ''s willing obedience replacing animal sacrifices.'),
('Hebrews', 10, 'adults', 3, 'What is the result of the one offering of the body of Jesus Christ?', 'We are sanctified through the offering of the body of Jesus Christ once for all', 'We are partially cleansed needing further sacrifices', 'We are given a chance to earn our own salvation', 'We receive temporary forgiveness only', 'a', 'Hebrews 10:10 — "By the which will we are sanctified through the offering of the body of Jesus Christ once for all."'),
('Hebrews', 10, 'adults', 4, 'What did Christ do after offering one sacrifice for sins forever?', 'He sat down on the right hand of God, from henceforth expecting till his enemies be made his footstool', 'He continued to offer daily sacrifices', 'He returned to earth immediately', 'He entered a state of rest and inactivity', 'a', 'Hebrews 10:12-13 — "But this man, after he had offered one sacrifice for sins for ever, sat down on the right hand of God; From henceforth expecting till his enemies be made his footstool."'),
('Hebrews', 10, 'adults', 5, 'What does the author say about wilful sin after receiving the knowledge of the truth?', 'There remaineth no more sacrifice for sins, but a certain fearful looking for of judgment and fiery indignation which shall devour the adversaries', 'Another sacrifice will be provided', 'Willful sin carries no consequences', 'God will simply overlook it', 'a', 'Hebrews 10:26-27 — "For if we sin wilfully after that we have received the knowledge of the truth, there remaineth no more sacrifice for sins, But a certain fearful looking for of judgment and fiery indignation, which shall devour the adversaries."'),
('Hebrews', 10, 'adults', 6, 'What sorer punishment does the author warn about?', 'He that despised Moses'' law died without mercy under two or three witnesses — of how much sorer punishment shall he be thought worthy who hath trodden under foot the Son of God', 'The punishment is identical to Moses'' law', 'There is no punishment under the new covenant', 'Only a mild rebuke is warranted', 'a', 'Hebrews 10:28-29 — "He that despised Moses'' law died without mercy under two or three witnesses: Of how much sorer punishment, suppose ye, shall he be thought worthy, who hath trodden under foot the Son of God, and hath counted the blood of the covenant, wherewith he was sanctified, an unholy thing."'),
('Hebrews', 10, 'adults', 7, 'What does the author remind them about their earlier faith?', 'They endured a great fight of afflictions, were made a gazingstock by reproaches and afflictions, had compassion on prisoners, and took joyfully the spoiling of their goods knowing they had in heaven a better and enduring substance', 'They had always lived comfortable lives', 'They had never faced any persecution', 'They had compromised their faith from the beginning', 'a', 'Hebrews 10:32-34 — "But call to remembrance the former days, in which, after ye were illuminated, ye endured a great fight of afflictions... and took joyfully the spoiling of your goods, knowing in yourselves that ye have in heaven a better and an enduring substance."'),
('Hebrews', 10, 'adults', 8, 'What Old Testament quote does the author use about the just living by faith?', 'The just shall live by faith — from Habakkuk 2:3-4; and if any man draw back, my soul shall have no pleasure in him', 'Deuteronomy 6:4 — Hear O Israel', 'Genesis 15:6 — Abraham believed God', 'Psalm 23:1 — The Lord is my shepherd', 'a', 'Hebrews 10:38 — "Now the just shall live by faith: but if any man draw back, my soul shall have no pleasure in him." This quotes Habakkuk 2:3-4.');

-- ═══════════════ CHAPTERS 11–13 ═══════════════

-- ═══ Hebrews Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Hebrews', 11, 'kids', 1, 'What is faith?', 'The substance of things hoped for, the evidence of things not seen', 'Believing only what you can see', 'Being afraid of everything', 'Knowing everything about God', 'a', 'Hebrews 11:1 — "Now faith is the substance of things hoped for, the evidence of things not seen."'),
('Hebrews', 11, 'kids', 2, 'What did Noah build by faith?', 'An ark to save his family', 'A tall tower', 'A big city', 'A beautiful garden', 'a', 'Hebrews 11:7 — "By faith Noah, being warned of God of things not seen as yet, moved with fear, prepared an ark to the saving of his house."'),
('Hebrews', 11, 'kids', 3, 'What did Abraham do when God told him to go to a new place?', 'He obeyed and went out, not knowing where he was going', 'He refused to leave his home', 'He asked for a map first', 'He sent someone else instead', 'a', 'Hebrews 11:8 — "By faith Abraham, when he was called to go out into a place which he should after receive for an inheritance, obeyed; and he went out, not knowing whither he went."'),
-- Teens
('Hebrews', 11, 'teens', 1, 'What do we understand by faith about the worlds?', 'The worlds were framed by the word of God, so that things which are seen were not made of things which do appear', 'The world created itself by accident', 'The world has always existed', 'We cannot know anything about creation', 'a', 'Hebrews 11:3 — "Through faith we understand that the worlds were framed by the word of God, so that things which are seen were not made of things which do appear."'),
('Hebrews', 11, 'teens', 2, 'What happened to Enoch by faith?', 'He was translated (taken up) that he should not see death, because God had testified he pleased God', 'He became the oldest person ever', 'He built a city in God''s name', 'He defeated a great army', 'a', 'Hebrews 11:5 — "By faith Enoch was translated that he should not see death; and was not found, because God had translated him: for before his translation he had this testimony, that he pleased God."'),
('Hebrews', 11, 'teens', 3, 'What is impossible without faith?', 'It is impossible to please God — for he that cometh to God must believe that he is and that he is a rewarder of them that diligently seek him', 'It is impossible to earn a living', 'It is impossible to make friends', 'It is impossible to travel safely', 'a', 'Hebrews 11:6 — "But without faith it is impossible to please him: for he that cometh to God must believe that he is, and that he is a rewarder of them that diligently seek him."'),
('Hebrews', 11, 'teens', 4, 'What did Moses choose by faith?', 'Rather to suffer affliction with the people of God than to enjoy the pleasures of sin for a season', 'To stay in Pharaoh''s palace forever', 'To become pharaoh of Egypt', 'To ignore God''s call and live comfortably', 'a', 'Hebrews 11:25 — "Choosing rather to suffer affliction with the people of God, than to enjoy the pleasures of sin for a season."'),
('Hebrews', 11, 'teens', 5, 'Did these faithful heroes receive what was promised?', 'No — they all died in faith, not having received the promises, but having seen them afar off', 'Yes, they all received everything immediately', 'Only some of them received the promises', 'They didn''t care about the promises', 'a', 'Hebrews 11:13 — "These all died in faith, not having received the promises, but having seen them afar off, and were persuaded of them, and embraced them, and confessed that they were strangers and pilgrims on the earth."'),
-- Adults
('Hebrews', 11, 'adults', 1, 'What two key elements define faith in verse 1?', 'The substance (hupostasis — assurance/confidence) of things hoped for, and the evidence (elegchos — conviction/proof) of things not seen', 'Blind acceptance and emotional feeling', 'Intellectual agreement and verbal confession', 'Ritual observance and legal compliance', 'a', 'Hebrews 11:1 — "Now faith is the substance of things hoped for, the evidence of things not seen." The Greek words imply confident assurance and inner conviction.'),
('Hebrews', 11, 'adults', 2, 'What does the author say the elders obtained by faith?', 'A good report — by faith the elders obtained a good report', 'Great wealth and power', 'Freedom from all suffering', 'Immediate fulfilment of all promises', 'a', 'Hebrews 11:2 — "For by it the elders obtained a good report."'),
('Hebrews', 11, 'adults', 3, 'What did Abraham look for by faith?', 'A city which hath foundations, whose builder and maker is God', 'A large estate in Canaan', 'A palace in Mesopotamia', 'A kingdom on earth', 'a', 'Hebrews 11:10 — "For he looked for a city which hath foundations, whose builder and maker is God."'),
('Hebrews', 11, 'adults', 4, 'What did Moses esteem greater than the treasures in Egypt?', 'The reproach of Christ — for he had respect unto the recompence of the reward', 'The gold of Solomon''s temple', 'The approval of Pharaoh', 'The wisdom of Egyptian scholars', 'a', 'Hebrews 11:26 — "Esteeming the reproach of Christ greater riches than the treasures in Egypt: for he had respect unto the recompence of the reward."'),
('Hebrews', 11, 'adults', 5, 'What did the faith heroes endure according to verses 35-38?', 'Torture not accepting deliverance, mockings, scourgings, bonds, imprisonment, stoning, being sawn asunder, slain with the sword, destitute, afflicted, tormented — of whom the world was not worthy', 'Comfortable and prosperous lives', 'Only minor inconveniences', 'Temporary setbacks followed by great success', 'a', 'Hebrews 11:35-38 — "Others were tortured... had trial of cruel mockings and scourgings... bonds and imprisonment: They were stoned, they were sawn asunder... being destitute, afflicted, tormented; (Of whom the world was not worthy.)"'),
('Hebrews', 11, 'adults', 6, 'Why had these heroes not received the promise?', 'God having provided some better thing for us, that they without us should not be made perfect', 'God forgot his promise to them', 'Their faith was insufficient', 'The promise was withdrawn', 'a', 'Hebrews 11:40 — "God having provided some better thing for us, that they without us should not be made perfect."'),
('Hebrews', 11, 'adults', 7, 'What does "by faith he forsook Egypt, not fearing the wrath of the king" reveal about Moses?', 'Moses endured as seeing him who is invisible — his faith enabled him to look beyond the visible threat of Pharaoh to the invisible reality of God', 'Moses was unaware of any danger', 'Moses had a powerful army to protect him', 'Moses was not afraid of anything natural or supernatural', 'a', 'Hebrews 11:27 — "By faith he forsook Egypt, not fearing the wrath of the king: for he endured, as seeing him who is invisible."'),
('Hebrews', 11, 'adults', 8, 'What does the phrase "of whom the world was not worthy" mean?', 'The world did not deserve these faithful believers — their suffering was not a sign of unworthiness but of the world''s unworthiness of them', 'The world rejected them because they were unimportant', 'They were too good for any earthly community', 'The world had no use for religious people', 'a', 'Hebrews 11:38 — "(Of whom the world was not worthy:) they wandered in deserts, and in mountains, and in dens and caves of the earth."');

-- ═══ Hebrews Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Hebrews', 12, 'kids', 1, 'Who should we look to as we run our race of faith?', 'Jesus — the author and finisher of our faith', 'Famous athletes', 'Rich and powerful kings', 'Popular teachers', 'a', 'Hebrews 12:2 — "Looking unto Jesus the author and finisher of our faith."'),
('Hebrews', 12, 'kids', 2, 'Why does God correct (discipline) us?', 'Because he loves us, like a good father', 'Because he is angry at us', 'Because he wants to hurt us', 'Because he doesn''t care about us', 'a', 'Hebrews 12:6 — "For whom the Lord loveth he chasteneth."'),
('Hebrews', 12, 'kids', 3, 'What should we try to have with everyone?', 'Peace — follow peace with all men', 'Fights and arguments', 'More money than them', 'More popularity than them', 'a', 'Hebrews 12:14 — "Follow peace with all men, and holiness, without which no man shall see the Lord."'),
-- Teens
('Hebrews', 12, 'teens', 1, 'What are we surrounded by according to this chapter?', 'A great cloud of witnesses — the faithful heroes from chapter 11', 'A great army of soldiers', 'A great crowd of strangers', 'A great wall of protection', 'a', 'Hebrews 12:1 — "Wherefore seeing we also are compassed about with so great a cloud of witnesses."'),
('Hebrews', 12, 'teens', 2, 'What should we lay aside to run the race?', 'Every weight and the sin which doth so easily beset us, running with patience', 'Our responsibilities and duties', 'Our friendships and relationships', 'Our knowledge and education', 'a', 'Hebrews 12:1 — "Let us lay aside every weight, and the sin which doth so easily beset us, and let us run with patience the race that is set before us."'),
('Hebrews', 12, 'teens', 3, 'What did Jesus endure for the joy set before him?', 'The cross, despising the shame, and is set down at the right hand of the throne of God', 'Only a small inconvenience', 'A comfortable and pleasant life', 'A brief moment of sadness', 'a', 'Hebrews 12:2 — "Who for the joy that was set before him endured the cross, despising the shame, and is set down at the right hand of the throne of God."'),
('Hebrews', 12, 'teens', 4, 'What does God''s chastening (discipline) produce afterward?', 'The peaceable fruit of righteousness unto them which are exercised thereby', 'Anger and bitterness', 'Confusion and doubt', 'Sadness that never ends', 'a', 'Hebrews 12:11 — "Now no chastening for the present seemeth to be joyous, but grievous: nevertheless afterward it yieldeth the peaceable fruit of righteousness unto them which are exercised thereby."'),
('Hebrews', 12, 'teens', 5, 'What does the author say our God is?', 'A consuming fire', 'A distant observer', 'An indifferent force', 'A lenient judge', 'a', 'Hebrews 12:29 — "For our God is a consuming fire."'),
-- Adults
('Hebrews', 12, 'adults', 1, 'What does "looking unto Jesus the author and finisher of our faith" mean?', 'Jesus is both the originator (archēgos) and perfecter (teleiōtēs) of faith — he began it and will bring it to completion', 'We should literally stare at a picture of Jesus', 'Jesus wrote the Bible by himself', 'Jesus will finish building the church building', 'a', 'Hebrews 12:2 — "Looking unto Jesus the author and finisher of our faith; who for the joy that was set before him endured the cross, despising the shame, and is set down at the right hand of the throne of God."'),
('Hebrews', 12, 'adults', 2, 'What does the author argue about chastening proving sonship?', 'If ye be without chastisement, whereof all are partakers, then are ye bastards and not sons — discipline proves legitimate sonship', 'Chastisement is a sign of God''s rejection', 'Only sinners receive God''s discipline', 'Discipline is never from God', 'a', 'Hebrews 12:8 — "But if ye be without chastisement, whereof all are partakers, then are ye bastards, and not sons."'),
('Hebrews', 12, 'adults', 3, 'What contrast does the author draw between Sinai and Sion?', 'They are not come to the mount that burned with fire and darkness and tempest (Sinai), but unto mount Sion, the city of the living God, the heavenly Jerusalem, and to an innumerable company of angels', 'Sinai and Sion are the same place', 'Sion is a physical mountain in Israel', 'Sinai is the better destination', 'a', 'Hebrews 12:18,22 — "For ye are not come unto the mount that might be touched, and that burned with fire... But ye are come unto mount Sion, and unto the city of the living God, the heavenly Jerusalem, and to an innumerable company of angels."'),
('Hebrews', 12, 'adults', 4, 'Who does the author say believers have come to at mount Sion?', 'God the Judge of all, the spirits of just men made perfect, Jesus the mediator of the new covenant, and the blood of sprinkling that speaketh better things than that of Abel', 'Moses and the prophets only', 'Angels and cherubim only', 'The patriarchs and their families only', 'a', 'Hebrews 12:23-24 — "To God the Judge of all, and to the spirits of just men made perfect, And to Jesus the mediator of the new covenant, and to the blood of sprinkling, that speaketh better things than that of Abel."'),
('Hebrews', 12, 'adults', 5, 'What does Abel''s blood cry versus Christ''s blood?', 'Abel''s blood cried for vengeance; Christ''s blood speaks better things — forgiveness and reconciliation', 'Both cry for the same thing', 'Abel''s blood is silent', 'Christ''s blood cries for judgment', 'a', 'Hebrews 12:24 — "The blood of sprinkling, that speaketh better things than that of Abel." Abel''s blood cried from the ground for justice (Genesis 4:10); Christ''s blood speaks of mercy and forgiveness.'),
('Hebrews', 12, 'adults', 6, 'What does "yet once more" signify about the shaking?', 'The removing of those things that are shaken — things that are made — that those things which cannot be shaken may remain, referring to the eternal kingdom', 'A minor earthquake with no significance', 'A political upheaval in Rome', 'A temporary disruption soon resolved', 'a', 'Hebrews 12:27 — "And this word, Yet once more, signifieth the removing of those things that are shaken, as of things that are made, that those things which cannot be shaken may remain."'),
('Hebrews', 12, 'adults', 7, 'What does the author urge about receiving a kingdom that cannot be moved?', 'Let us have grace, whereby we may serve God acceptably with reverence and godly fear', 'Let us celebrate with worldly festivities', 'Let us rest from all service', 'Let us demand our rights as citizens', 'a', 'Hebrews 12:28 — "Wherefore we receiving a kingdom which cannot be moved, let us have grace, whereby we may serve God acceptably with reverence and godly fear."'),
('Hebrews', 12, 'adults', 8, 'What does "follow peace with all men, and holiness, without which no man shall see the Lord" teach?', 'Both peace and holiness are essential — peace with others and personal holiness are not optional for those who will see God', 'Only peace matters, not holiness', 'Only holiness matters, not peace', 'Neither peace nor holiness is required to see God', 'a', 'Hebrews 12:14 — "Follow peace with all men, and holiness, without which no man shall see the Lord."');

-- ═══ Hebrews Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Hebrews', 13, 'kids', 1, 'What should we continue to show?', 'Brotherly love — let brotherly love continue', 'Anger and fighting', 'Selfishness and greed', 'Fear and worry', 'a', 'Hebrews 13:1 — "Let brotherly love continue."'),
('Hebrews', 13, 'kids', 2, 'Does Jesus ever change?', 'No — Jesus Christ is the same yesterday, and to day, and for ever', 'Yes, he changes all the time', 'He changes every hundred years', 'Only God the Father never changes', 'a', 'Hebrews 13:8 — "Jesus Christ the same yesterday, and to day, and for ever."'),
('Hebrews', 13, 'kids', 3, 'What has God promised he will never do?', 'He will never leave us nor forsake us', 'He will never listen to our prayers', 'He will never help us again', 'He will never forgive us', 'a', 'Hebrews 13:5 — "For he hath said, I will never leave thee, nor forsake thee."'),
-- Teens
('Hebrews', 13, 'teens', 1, 'What might happen when we entertain strangers?', 'Some have entertained angels unawares', 'We might lose all our money', 'We might get in trouble with the law', 'Nothing special ever happens', 'a', 'Hebrews 13:2 — "Be not forgetful to entertain strangers: for thereby some have entertained angels unawares."'),
('Hebrews', 13, 'teens', 2, 'What does the author say about marriage?', 'Marriage is honourable in all, and the bed undefiled; but whoremongers and adulterers God will judge', 'Marriage is only for the wealthy', 'Marriage is outdated and unnecessary', 'Marriage is honourable only for priests', 'a', 'Hebrews 13:4 — "Marriage is honourable in all, and the bed undefiled: but whoremongers and adulterers God will judge."'),
('Hebrews', 13, 'teens', 3, 'What should our conversation (way of life) be free from?', 'Covetousness — be content with such things as ye have, for God hath said I will never leave thee nor forsake thee', 'All human interaction', 'All forms of happiness', 'All kinds of work', 'a', 'Hebrews 13:5 — "Let your conversation be without covetousness; and be content with such things as ye have: for he hath said, I will never leave thee, nor forsake thee."'),
('Hebrews', 13, 'teens', 4, 'What sacrifice does God want us to offer continually?', 'The sacrifice of praise to God, that is, the fruit of our lips giving thanks to his name', 'Animal sacrifices in the temple', 'Burnt offerings of grain and oil', 'Large financial donations', 'a', 'Hebrews 13:15 — "By him therefore let us offer the sacrifice of praise to God continually, that is, the fruit of our lips giving thanks to his name."'),
('Hebrews', 13, 'teens', 5, 'What can we boldly say because God will never leave us?', 'The Lord is my helper, and I will not fear what man shall do unto me', 'I am the greatest person alive', 'I will never have any problems', 'I will always be wealthy and comfortable', 'a', 'Hebrews 13:6 — "So that we may boldly say, The Lord is my helper, and I will not fear what man shall do unto me."'),
-- Adults
('Hebrews', 13, 'adults', 1, 'What does "Jesus Christ the same yesterday, and to day, and for ever" affirm?', 'The immutability and eternality of Christ — he does not change in his nature, character, or purposes across all time', 'Jesus adapts his character to each generation', 'This refers only to his earthly ministry', 'Christ changes with the times', 'a', 'Hebrews 13:8 — "Jesus Christ the same yesterday, and to day, and for ever." This verse affirms Christ''s divine immutability.'),
('Hebrews', 13, 'adults', 2, 'What does "let us go forth therefore unto him without the camp, bearing his reproach" mean?', 'Believers should be willing to separate from established religious systems and bear the social cost of identifying with Christ, as he suffered outside the gate', 'We should literally live outside the city walls', 'We should abandon all community', 'We should join a different religion', 'a', 'Hebrews 13:13 — "Let us go forth therefore unto him without the camp, bearing his reproach." Jesus suffered outside the gate of Jerusalem (v.12); believers follow him outside human religious systems.'),
('Hebrews', 13, 'adults', 3, 'What does "we have an altar" refer to?', 'Christ''s cross as the altar from which the new covenant community feeds — those who serve the old tabernacle have no right to eat from this altar', 'A physical altar in a church building', 'The altar of incense in the temple', 'A metaphorical table of fellowship', 'a', 'Hebrews 13:10 — "We have an altar, whereof they have no right to eat which serve the tabernacle."'),
('Hebrews', 13, 'adults', 4, 'Why did Jesus suffer without the gate?', 'That he might sanctify the people with his own blood', 'Because there was no room inside the city', 'Because Roman law required it', 'Because the temple was too crowded', 'a', 'Hebrews 13:12 — "Wherefore Jesus also, that he might sanctify the people with his own blood, suffered without the gate."'),
('Hebrews', 13, 'adults', 5, 'What two types of sacrifices does the author urge?', 'The sacrifice of praise (fruit of lips giving thanks) and doing good and communicating (sharing), for with such sacrifices God is well pleased', 'Animal sacrifices and grain offerings', 'Fasting and prayer only', 'Financial tithes and building projects', 'a', 'Hebrews 13:15-16 — "By him therefore let us offer the sacrifice of praise to God continually, that is, the fruit of our lips giving thanks to his name. But to do good and to communicate forget not: for with such sacrifices God is well pleased."'),
('Hebrews', 13, 'adults', 6, 'What does the author say about obeying spiritual leaders?', 'Obey them that have the rule over you, and submit yourselves, for they watch for your souls as they that must give account — that they may do it with joy and not with grief', 'Spiritual leaders have no authority at all', 'Leaders should never be questioned or obeyed', 'Leaders are accountable to no one', 'a', 'Hebrews 13:17 — "Obey them that have the rule over you, and submit yourselves: for they watch for your souls, as they that must give account, that they may do it with joy, and not with grief: for that is unprofitable for you."'),
('Hebrews', 13, 'adults', 7, 'What benediction does the author give about the God of peace?', 'The God of peace, that brought again from the dead our Lord Jesus, that great shepherd of the sheep, through the blood of the everlasting covenant, make you perfect in every good work to do his will', 'May the God of war give you victory', 'May the God of wisdom grant you knowledge', 'May the God of abundance make you wealthy', 'a', 'Hebrews 13:20-21 — "Now the God of peace, that brought again from the dead our Lord Jesus, that great shepherd of the sheep, through the blood of the everlasting covenant, Make you perfect in every good work to do his will."'),
('Hebrews', 13, 'adults', 8, 'What does the phrase "the blood of the everlasting covenant" signify?', 'Christ''s blood ratifies an eternal covenant — unlike the temporary Mosaic covenant, this covenant is everlasting because it is sealed by the blood of the eternal Son', 'The blood of animals that was shed repeatedly', 'A symbolic reference with no real substance', 'The blood of the martyrs throughout history', 'a', 'Hebrews 13:20 — "Through the blood of the everlasting covenant." This phrase connects Christ''s death to the establishment of an eternal covenant that supersedes all previous covenants.');
